SELECT MAX(confidence_level) AS max_confidence, MAX(analysis_date) AS latest_analysis_date
FROM analysis_steps
WHERE step_id = 1;

SELECT step_id, strftime('%Y-%m-%d', analysis_date) AS analysis_date
FROM analysis_steps
WHERE output_data = 'output_data_2.csv';

SELECT collaboration_id
FROM collaborations
WHERE team_id = (SELECT team_id FROM teams WHERE team_name = 'Marketing Team');

SELECT COUNT(*) AS total_successful_executions
FROM model_steps
WHERE execution_status = 'success';

SELECT DISTINCT M.model_name
FROM models M
JOIN reports R ON M.model_id = R.model_id;
